   ```c
   #include <SDL2/SDL.h>
   #include <stdio.h>
   #include <stdlib.h>

   // Function to handle key press events
   void handleKeyPress(SDL_KeyboardEvent event, FILE *log_file) {
       fprintf(log_file, "Key %s pressed\n", SDL_GetKeyName(event.keysym.sym));
   }

   // Function to handle key release events
   void handleKeyRelease(SDL_KeyboardEvent event, FILE *log_file) {
       fprintf(log_file, "Key %s released\n", SDL_GetKeyName(event.keysym.sym));
   }

   int main(int argc, char* argv[]) {
       SDL_Init(SDL_INIT_VIDEO | SDL_INIT_EVENTS);

       SDL_Window* window = SDL_CreateWindow(
           "Key Event Logger",
           SDL_WINDOWPOS_UNDEFINED,
           SDL_WINDOWPOS_UNDEFINED,
           640, 480,
           SDL_WINDOW_SHOWN
       );

       SDL_Renderer* renderer = SDL_CreateRenderer(window, -1, SDL_RENDERER_ACCELERATED);

       SDL_Event event;

       FILE *log_file = fopen("key_events.log", "w");

       if (!log_file) {
           fprintf(stderr, "Failed to open log file\n");
           return 1;
       }

       bool running = true;
       while (running) {
           while (SDL_PollEvent(&event)) {
               if (event.type == SDL_QUIT) {
                   running = false;
               } else if (event.type == SDL_KEYDOWN) {
                   handleKeyPress(event.key, log_file);
               } else if (event.type == SDL_KEYUP) {
                   handleKeyRelease(event.key, log_file);
               }
           }

           // Render loop (optional)
           SDL_SetRenderDrawColor(renderer, 0, 0, 0, 255);
           SDL_RenderClear(renderer);
           SDL_RenderPresent(renderer);
       }

       fclose(log_file);
       SDL_DestroyRenderer(renderer);
       SDL_DestroyWindow(window);
       SDL_Quit();

       return 0;
   }
   ```

