       if event.type == pygame.KEYDOWN:
           key_states[event.key] = True
           timestamp = datetime.datetime.now().strftime("%Y-%m-%d %H:%M:%S")
           log_file.write(f"{timestamp} - Key {pygame.key.name(event.key)} pressed\n")
